import std.stdio;

class MyClass
{
    // Private member variable
    private int _value;

    // Constructor
    this(int startingValue)
    {
        this._value = startingValue;
    }

    // Public method
    public void printValue()
    {
        writeln("The value is: ", _value);
    }
}

void main()
{
    auto instance = new MyClass(42);
    instance.printValue();
}
